`, "",{"version":3,"sources":["webpack://./src/components/ProjectPerformancePanel.vue"],"names":[],"mappings":";AAkoCA;EACA,gCAAA;EACA,uCAAA;EACA,6DAAA;EACA,sCAAA;EACA,gBAAA;AACA;AAEA;EACA,gBAAA;EACA,gBAAA;EACA,gBAAA;EACA,gBAAA;EACA,iBAAA;AACA;;AAEA,WAAA;AACA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;EACA,wDAAA;EACA,eAAA;EACA,iBAAA;EACA,4BAAA;AACA;AAEA;EACA,mBAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,yCAAA;EACA,SAAA;EACA,UAAA;EACA,YAAA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;AACA;AAEA;EACA,cAAA;AACA;AAEA;EACA,uCAAA;EACA,0BAAA;AACA;AAEA;EACA,yBAAA;AACA;;AAEA,UAAA;AACA;EACA,aAAA;EACA,qCAAA;EACA,4BAAA;EACA,sCAAA;EACA,kCAAA;AACA;AAEA;EACA,aAAA;EACA,qCAAA;EACA,4BAAA;EACA,0DAAA;AACA;;AAEA,SAAA;AACA;EACA,gCAAA;EACA,uCAAA;EACA,6DAAA;EACA,gCAAA;EACA,sDAAA;AACA;AAEA;EACA,mEAAA;AACA;AAEA;EACA,eAAA;EACA,kBAAA;AACA;AAEA;EACA,2BAAA;AACA;AAEA;EACA,aAAA;EACA,uBAAA;EACA,8BAAA;AACA;AAEA;EACA,uCAAA;EACA,UAAA;EACA,8CAAA;EACA,cAAA;EACA,eAAA;AACA;AAEA;EACA,UAAA;EACA,cAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,yCAAA;EACA,oCAAA;EACA,iBAAA;EACA,UAAA;EACA,YAAA;AACA;AAEA;EACA,WAAA;EACA,WAAA;EACA,yBAAA;EACA,kBAAA;EACA,sCAAA;AACA;AAEA;EACA,eAAA;EACA,uCAAA;EACA,qCAAA;EACA,gBAAA;AACA;;AAEA,kBAAA;AACA;EACA,aAAA;EACA,sBAAA;EACA,4BAAA;AACA;AAEA;EACA,aAAA;EACA,sBAAA;EACA,QAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;AACA;AAEA;EACA,eAAA;EACA,yCAAA;EACA,gBAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,yCAAA;AACA;AAEA;EACA,WAAA;EACA,WAAA;EACA,yBAAA;EACA,kBAAA;EACA,gBAAA;AACA;AAEA;EACA,YAAA;EACA,oDAAA;EACA,kBAAA;EACA,2BAAA;AACA;AAEA;EACA,gBAAA;EACA,eAAA;EACA,uCAAA;AACA;;AAEA,4BAAA;AACA;EACA,aAAA;EACA,sBAAA;EACA,4BAAA;AACA;AAEA;EACA,aAAA;EACA,sBAAA;EACA,QAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;EACA,YAAA;EACA,OAAA;AACA;AAEA;EACA,WAAA;EACA,YAAA;EACA,kBAAA;EACA,qDAAA;EACA,WAAA;EACA,eAAA;EACA,gBAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,cAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;EACA,cAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,uCAAA;AACA;;AAEA,wBAAA;AACA;EACA,aAAA;EACA,mBAAA;EACA,SAAA;EACA,OAAA;EACA,YAAA;AACA;AAEA;EACA,WAAA;EACA,YAAA;EACA,kBAAA;EACA,qDAAA;EACA,WAAA;EACA,eAAA;EACA,gBAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,cAAA;AACA;;AAEA,yCAAA;AACA;EACA,aAAA;EACA,SAAA;EACA,uBAAA;AACA;;AAEA,yBAAA;AACA;EACA,YAAA;EACA,gBAAA;EACA,aAAA;EACA,sBAAA;EACA,yBAAA;EACA,kBAAA;EACA,gBAAA;EACA,mBAAA;AACA;AAEA;EACA,WAAA;EACA,iBAAA;EACA,YAAA;EACA,gCAAA;EACA,eAAA;EACA,yCAAA;EACA,uBAAA;EACA,aAAA;EACA,sBAAA;AACA;AAEA;EACA,cAAA;AACA;AAEA;EACA,WAAA;EACA,gBAAA;EACA,YAAA;EACA,gCAAA;EACA,eAAA;EACA,yCAAA;EACA,uBAAA;EACA,aAAA;EACA,sBAAA;EACA,eAAA;EACA,wBAAA;EACA,qBAAA;EACA,gBAAA;EACA,yDAAA;EACA,4BAAA;EACA,qCAAA;EACA,mBAAA;AACA;AAEA;EACA,gBAAA;EACA,aAAA;AACA;AAEA;EACA,UAAA;AACA;AAEA;EACA,mBAAA;EACA,kBAAA;AACA;AAEA;EACA,iBAAA;EACA,eAAA;EACA,yCAAA;EACA,eAAA;EACA,4BAAA;EACA,mBAAA;EACA,gBAAA;EACA,uBAAA;EACA,kCAAA;AACA;AAEA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;EACA,gBAAA;EACA,0BAAA;AACA;AAEA;EACA,aAAA;EACA,eAAA;EACA,cAAA;EACA,kBAAA;AACA;;AAEA,gCAAA;AACA;EACA,OAAA;EACA,YAAA;AACA;;AAEA,yDAAA;AACA;EACA,UAAA;EACA,eAAA;AACA;AAEA;EACA,cAAA;AACA;;AAEA,qDAAA;AAEA;EACA,eAAA;EACA,MAAA;EACA,OAAA;EACA,QAAA;EACA,SAAA;EACA,+BAAA;EACA,cAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,aAAA;EACA,2CAAA;AACA;AAEA;AACA;IACA,UAAA;AACA;AACA;IACA,UAAA;AACA;AACA;AAEA;EACA,gBAAA;EACA,mBAAA;EACA,0CAAA;EACA,WAAA;EACA,gBAAA;EACA,gBAAA;EACA,aAAA;EACA,sBAAA;EACA,2CAAA;AACA;AAEA;AACA;IACA,UAAA;IACA,2BAAA;AACA;AACA;IACA,UAAA;IACA,wBAAA;AACA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;EACA,kBAAA;EACA,gCAAA;EACA,cAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,SAAA;EACA,UAAA;EACA,YAAA;AACA;AAEA;EACA,gBAAA;EACA,YAAA;EACA,eAAA;EACA,cAAA;EACA,eAAA;EACA,WAAA;EACA,YAAA;EACA,kBAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,yCAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,uBAAA;EACA,gBAAA;EACA,OAAA;AACA;AAEA;EACA,UAAA;AACA;AAEA;EACA,mBAAA;EACA,kBAAA;AACA;;AAEA,gBAAA;AACA;EACA,mBAAA;EACA,yBAAA;EACA,mBAAA;EACA,gBAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;EACA,kBAAA;EACA,eAAA;EACA,4BAAA;EACA,SAAA;AACA;AAEA;EACA,mBAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,OAAA;EACA,YAAA;EACA,gBAAA;EACA,uBAAA;EACA,mBAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,iBAAA;EACA,mBAAA;EACA,yBAAA;EACA,gBAAA;EACA,cAAA;EACA,eAAA;EACA,mBAAA;EACA,yCAAA;AACA;AAEA;EACA,mBAAA;EACA,WAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;EACA,cAAA;EACA,eAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,+BAAA;EACA,oBAAA;EACA,gBAAA;AACA;AAEA;EACA,wBAAA;AACA;;AAEA,WAAA;AACA;EACA,eAAA;EACA,gBAAA;EACA,gBAAA;EACA,mBAAA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,WAAA;AACA;;AAEA,aAAA;AACA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;EACA,iBAAA;EACA,6BAAA;EACA,kBAAA;AACA;AAEA;EACA,eAAA;EACA,WAAA;EACA,gBAAA;AACA;AAEA;EACA,eAAA;EACA,iBAAA;EACA,mBAAA;EACA,sBAAA;EACA,gBAAA;EACA,WAAA;EACA,eAAA;EACA,0BAAA;AACA;AAEA;EACA,kBAAA;AACA;AAEA;EACA,mBAAA;EACA,WAAA;EACA,qBAAA;AACA;;AAEA,uBAAA;AACA;EACA,qBAAA;EACA,gBAAA;EACA,mBAAA;EACA,eAAA;EACA,gBAAA;EACA,mBAAA;EACA,WAAA;EACA,mBAAA;AACA;;AAEA,0BAAA;AACA;EACA,WAAA;EACA,mBAAA;AACA;AAEA;EACA,YAAA;EACA,oDAAA;EACA,2BAAA;AACA;;AAEA,eAAA;AACA;EACA,oBAAA;EACA,mBAAA;AACA;AAEA;EACA,WAAA;EACA,yBAAA;EACA,eAAA;AACA;AAEA;EACA,gBAAA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,yBAAA;EACA,sBAAA;EACA,qBAAA;EACA,gCAAA;AACA;AAEA;EACA,YAAA;EACA,cAAA;EACA,gCAAA;EACA,sBAAA;AACA;AAEA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;AACA;;AAEA,8BAAA;AACA;;EAEA,eAAA;EACA,gBAAA;EACA,gBAAA;EACA,mBAAA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,eAAA;EACA,mBAAA;EACA,cAAA;EACA,gBAAA;EACA,kBAAA;EACA,mBAAA;AACA;;AAEA,iBAAA;AACA;EACA,kBAAA;EACA,kBAAA;EACA,cAAA;EACA,eAAA;AACA;AAEA;EACA,iBAAA;EACA,cAAA;EACA,eAAA;EACA,kBAAA;AACA;;AAEA,eAAA;AACA;;EAEA,yBAAA;EACA,gBAAA;AACA;AAEA;;EAEA,UAAA;EACA,aAAA;EACA,cAAA;EACA,iBAAA;AACA;;AAEA,eAAA;AACA;AACA;;IAEA,0BAAA;AACA;AAEA;IACA,eAAA;IACA,gBAAA;AACA;AACA","sourcesContent":["<template>\n  <component\n    :is=\"embedded ? 'div' : 'section'\"\n    :class=\"['perf-panel', { 'perf-panel--embedded': embedded }]\"\n  >\n    <!-- HEADER (standalone only) -->\n    <div\n      v-if=\"!embedded\"\n      class=\"perf-panel__header\"\n      @click=\"collapsed = !collapsed\"\n    >\n      <h3 class=\"perf-panel__title\">\n        <svg\n          xmlns=\"http://www.w3.org/2000/svg\"\n          width=\"18\"\n          height=\"18\"\n          viewBox=\"0 0 24 24\"\n          fill=\"none\"\n          stroke=\"currentColor\"\n          stroke-width=\"2\"\n          stroke-linecap=\"round\"\n          stroke-linejoin=\"round\"\n        >\n          <line x1=\"18\" y1=\"20\" x2=\"18\" y2=\"10\" />\n          <line x1=\"12\" y1=\"20\" x2=\"12\" y2=\"4\" />\n          <line x1=\"6\" y1=\"20\" x2=\"6\" y2=\"14\" />\n        </svg>\n        Project Performance Analytics\n      </h3>\n      <svg\n        xmlns=\"http://www.w3.org/2000/svg\"\n        width=\"18\"\n        height=\"18\"\n        viewBox=\"0 0 24 24\"\n        fill=\"none\"\n        stroke=\"currentColor\"\n        stroke-width=\"2\"\n        stroke-linecap=\"round\"\n        stroke-linejoin=\"round\"\n        class=\"perf-panel__chevron\"\n        :class=\"{ 'perf-panel__chevron--rotated': collapsed }\"\n      >\n        <polyline points=\"18 15 12 9 6 15\" />\n      </svg>\n    </div>\n\n    <div v-show=\"embedded || !collapsed\">\n      <!-- TOP ROW: Progress + Productivity -->\n      <div class=\"perf-panel__top-grid\">\n        <!-- Project Progress Comparison -->\n        <div\n          class=\"perf-panel__card perf-panel__card--clickable\"\n          @click=\"openModal('progress')\"\n        >\n          <div class=\"perf-panel__card-header-row\">\n            <h3 class=\"perf-panel__card-title\">\n              Project Progress<br />Comparison\n            </h3>\n            <span class=\"perf-panel__card-drill\" title=\"Click for details\">\n              <svg\n                xmlns=\"http://www.w3.org/2000/svg\"\n                width=\"16\"\n                height=\"16\"\n                viewBox=\"0 0 24 24\"\n                fill=\"none\"\n                stroke=\"currentColor\"\n                stroke-width=\"2\"\n                stroke-linecap=\"round\"\n                stroke-linejoin=\"round\"\n              >\n                <polyline points=\"15 3 21 3 21 9\" />\n                <line x1=\"10\" y1=\"14\" x2=\"21\" y2=\"3\" />\n                <path\n                  d=\"M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2h5\"\n                />\n              </svg>\n            </span>\n          </div>\n          <div class=\"perf-panel__card-title-underline\"></div>\n          <div class=\"perf-panel__bar-list\">\n            <div\n              v-for=\"(item, idx) in previewProjectProgress\"\n              :key=\"'prog-' + idx\"\n              class=\"perf-panel__bar-item\"\n            >\n              <div class=\"perf-panel__bar-row\">\n                <span class=\"perf-panel__bar-label\">{{ item.name }}</span>\n                <span class=\"perf-panel__bar-value\">{{ item.progress }}%</span>\n              </div>\n              <div class=\"perf-panel__bar-track\">\n                <div\n                  class=\"perf-panel__bar-fill\"\n                  :style=\"{ width: item.progress + '%' }\"\n                ></div>\n              </div>\n            </div>\n          </div>\n          <div\n            v-if=\"projectProgress.length > progressPreviewLimit\"\n            class=\"perf-panel__bar-hint\"\n          >\n            Showing {{ previewProjectProgress.length }} of\n            {{ projectProgress.length }} projects (click for full details)\n          </div>\n        </div>\n\n        <!-- Member Performance -->\n        <div\n          class=\"perf-panel__card perf-panel__card--clickable\"\n          @click=\"openModal('member')\"\n        >\n          <div class=\"perf-panel__card-header-row\">\n            <h3 class=\"perf-panel__card-title\">Member<br />Performance</h3>\n            <span class=\"perf-panel__card-drill\" title=\"Click for details\">\n              <svg\n                xmlns=\"http://www.w3.org/2000/svg\"\n                width=\"16\"\n                height=\"16\"\n                viewBox=\"0 0 24 24\"\n                fill=\"none\"\n                stroke=\"currentColor\"\n                stroke-width=\"2\"\n                stroke-linecap=\"round\"\n                stroke-linejoin=\"round\"\n              >\n                <polyline points=\"15 3 21 3 21 9\" />\n                <line x1=\"10\" y1=\"14\" x2=\"21\" y2=\"3\" />\n                <path\n                  d=\"M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2h5\"\n                />\n              </svg>\n            </span>\n          </div>\n          <div class=\"perf-panel__card-title-underline\"></div>\n          <p class=\"perf-panel__card-desc\">\n            Tasks completed per member vs assigned tasks\n          </p>\n          <div class=\"perf-panel__member-list\">\n            <div\n              v-for=\"(item, idx) in previewMemberPerformance\"\n              :key=\"'mem-' + idx\"\n              class=\"perf-panel__member-item\"\n            >\n              <div class=\"perf-panel__member-row\">\n                <div class=\"perf-panel__member-info\">\n                  <span class=\"perf-panel__member-avatar\">{{\n                    item.name.charAt(0).toUpperCase()\n                  }}</span>\n                  <span class=\"perf-panel__bar-label\">{{ item.name }}</span>\n                </div>\n                <span class=\"perf-panel__member-stats\">\n                  <span class=\"perf-panel__member-count\"\n                    >{{ item.done }}/{{ item.total }}</span\n                  >\n                  <span class=\"perf-panel__bar-value\"\n                    >{{ item.progress }}%</span\n                  >\n                </span>\n              </div>\n              <div class=\"perf-panel__bar-track\">\n                <div\n                  class=\"perf-panel__bar-fill\"\n                  :style=\"{ width: item.progress + '%' }\"\n                ></div>\n              </div>\n            </div>\n          </div>\n          <div\n            v-if=\"memberPerformance.length > memberPreviewLimit\"\n            class=\"perf-panel__bar-hint\"\n          >\n            Showing {{ previewMemberPerformance.length }} of\n            {{ memberPerformance.length }} members (click for full details)\n          </div>\n        </div>\n      </div>\n\n      <!-- BOTTOM ROW: Delay Donut + Completion Area -->\n      <div class=\"perf-panel__bottom-grid\">\n        <!-- Project Tasks Delay Overview -->\n        <div class=\"perf-panel__card\">\n          <div class=\"perf-panel__card-header-row\">\n            <h3 class=\"perf-panel__card-title\">\n              Project Tasks Delay<br />Overview\n            </h3>\n            <span\n              class=\"perf-panel__card-drill perf-panel__card-drill--visible\"\n              title=\"Click for details\"\n              @click=\"openModal('delay')\"\n            >\n              <svg\n                xmlns=\"http://www.w3.org/2000/svg\"\n                width=\"16\"\n                height=\"16\"\n                viewBox=\"0 0 24 24\"\n                fill=\"none\"\n                stroke=\"currentColor\"\n                stroke-width=\"2\"\n                stroke-linecap=\"round\"\n                stroke-linejoin=\"round\"\n              >\n                <polyline points=\"15 3 21 3 21 9\" />\n                <line x1=\"10\" y1=\"14\" x2=\"21\" y2=\"3\" />\n                <path\n                  d=\"M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2h5\"\n                />\n              </svg>\n            </span>\n          </div>\n          <div class=\"perf-panel__card-title-underline\"></div>\n\n          <div class=\"perf-panel__chart-row\">\n            <!-- Project list panel -->\n            <div class=\"perf-panel__proj-list\">\n              <input\n                v-model=\"delaySearch\"\n                class=\"perf-panel__proj-search\"\n                type=\"text\"\n                placeholder=\"Filter…\"\n                @click.stop\n              />\n              <select\n                v-model=\"delayStatusFilter\"\n                class=\"perf-panel__proj-status-filter\"\n                @click.stop\n              >\n                <option value=\"\">All Statuses</option>\n                <option value=\"Active\">Active</option>\n                <option value=\"Waiting on Customer\">W.o.c.</option>\n                <option value=\"On Hold\">On Hold</option>\n                <option value=\"Done\">Done</option>\n              </select>\n              <div class=\"perf-panel__proj-items\">\n                <div\n                  v-for=\"(proj, i) in filteredDelayProjects\"\n                  :key=\"'dp-' + i\"\n                  class=\"perf-panel__proj-item\"\n                  :class=\"{\n                    'perf-panel__proj-item--active':\n                      delayIndex === proj.originalIndex,\n                  }\"\n                  @click.stop=\"delayIndex = proj.originalIndex\"\n                >\n                  {{ proj.name }}\n                </div>\n                <div\n                  v-if=\"filteredDelayProjects.length === 0\"\n                  class=\"perf-panel__proj-empty\"\n                >\n                  No match\n                </div>\n              </div>\n            </div>\n            <!-- Chart -->\n            <div class=\"perf-panel__chart-area\">\n              <DonutChart\n                :key=\"'donut-' + delayIndex\"\n                :chart-data=\"activeDelayProject.chart\"\n              />\n            </div>\n          </div>\n        </div>\n\n        <!-- Task Completion Over Time -->\n        <div class=\"perf-panel__card\">\n          <div class=\"perf-panel__card-header-row\">\n            <h3 class=\"perf-panel__card-title\">\n              Task Completion<br />Over Time\n            </h3>\n            <span\n              class=\"perf-panel__card-drill perf-panel__card-drill--visible\"\n              title=\"Click for details\"\n              @click=\"openModal('completion')\"\n            >\n              <svg\n                xmlns=\"http://www.w3.org/2000/svg\"\n                width=\"16\"\n                height=\"16\"\n                viewBox=\"0 0 24 24\"\n                fill=\"none\"\n                stroke=\"currentColor\"\n                stroke-width=\"2\"\n                stroke-linecap=\"round\"\n                stroke-linejoin=\"round\"\n              >\n                <polyline points=\"15 3 21 3 21 9\" />\n                <line x1=\"10\" y1=\"14\" x2=\"21\" y2=\"3\" />\n                <path\n                  d=\"M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2h5\"\n                />\n              </svg>\n            </span>\n          </div>\n          <div class=\"perf-panel__card-title-underline\"></div>\n\n          <div class=\"perf-panel__chart-row\">\n            <!-- Project list panel -->\n            <div class=\"perf-panel__proj-list\">\n              <input\n                v-model=\"completionSearch\"\n                class=\"perf-panel__proj-search\"\n                type=\"text\"\n                placeholder=\"Filter…\"\n                @click.stop\n              />\n              <select\n                v-model=\"completionStatusFilter\"\n                class=\"perf-panel__proj-status-filter\"\n                @click.stop\n              >\n                <option value=\"\">All Statuses</option>\n                <option value=\"Active\">Active</option>\n                <option value=\"Waiting on Customer\">W.o.c.</option>\n                <option value=\"On Hold\">On Hold</option>\n                <option value=\"Done\">Done</option>\n              </select>\n              <div class=\"perf-panel__proj-items\">\n                <div\n                  v-for=\"(proj, i) in filteredCompletionProjects\"\n                  :key=\"'cp-' + i\"\n                  class=\"perf-panel__proj-item\"\n                  :class=\"{\n                    'perf-panel__proj-item--active':\n                      completionIndex === proj.originalIndex,\n                  }\"\n                  @click.stop=\"completionIndex = proj.originalIndex\"\n                >\n                  {{ proj.name }}\n                </div>\n                <div\n                  v-if=\"filteredCompletionProjects.length === 0\"\n                  class=\"perf-panel__proj-empty\"\n                >\n                  No match\n                </div>\n              </div>\n            </div>\n            <!-- Chart -->\n            <div class=\"perf-panel__chart-area\">\n              <AreaChart\n                :key=\"'area-' + completionIndex\"\n                :labels=\"activeCompletionProject.weeks\"\n                :data=\"activeCompletionProject.data\"\n              />\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- ── PER PROJECT DETAILS ── -->\n      <div class=\"perf-panel__project-details\">\n        <div class=\"perf-panel__card\">\n          <h3 class=\"perf-panel__card-title\">Per Project Details</h3>\n          <div class=\"perf-panel__card-title-underline\"></div>\n          <ProjectDetailsPanel ref=\"detailsPanel\" :projects=\"projectDetails\" />\n        </div>\n      </div>\n    </div>\n\n    <!-- DRILL-DOWN MODAL -->\n    <div v-if=\"modal\" class=\"perf-modal__backdrop\" @click.self=\"closeModal\">\n      <div class=\"perf-modal\">\n        <div class=\"perf-modal__header\">\n          <h3 class=\"perf-modal__title\">{{ modalTitle }}</h3>\n          <button class=\"perf-modal__close\" @click=\"closeModal\">&times;</button>\n        </div>\n        <div class=\"perf-modal__body\">\n          <!-- Progress Detail -->\n          <template v-if=\"modal === 'progress'\">\n            <div class=\"perf-modal__sort-bar\" @click.stop>\n              <span class=\"perf-modal__sort-label\">% Done:</span>\n              <button\n                class=\"perf-modal__sort-btn perf-modal__sort-btn--active\"\n                @click=\"\n                  progressSortBy = progressSortBy === 'desc' ? 'asc' : 'desc'\n                \"\n              >\n                {{ progressSortBy === \"desc\" ? \"High → Low\" : \"Low → High\" }}\n              </button>\n            </div>\n            <div\n              v-for=\"proj in sortedProgressDetails\"\n              :key=\"'mp-' + proj.name\"\n              class=\"perf-modal__project\"\n            >\n              <div\n                class=\"perf-modal__project-header\"\n                @click=\"toggleProject('progress', proj.name)\"\n              >\n                <span class=\"perf-modal__project-name\">{{ proj.name }}</span>\n                <div class=\"perf-modal__project-stats\">\n                  <button\n                    class=\"perf-modal__goto-btn\"\n                    title=\"Open in Per Project Details\"\n                    @click.stop=\"goToProjectDetails(proj)\"\n                  >\n                    &#8594; Details\n                  </button>\n                  <span class=\"perf-modal__badge perf-modal__badge--info\">\n                    {{ proj.done }}/{{ proj.total }} done\n                  </span>\n                  <span\n                    class=\"perf-modal__badge\"\n                    :class=\"progressBadgeClass(proj.progress)\"\n                  >\n                    {{ proj.progress }}%\n                  </span>\n                  <span\n                    class=\"perf-modal__chevron\"\n                    :class=\"{\n                      'perf-modal__chevron--open': isProjectOpen(\n                        'progress',\n                        proj.name,\n                      ),\n               